pythonCopierModifierimport importlib
import traceback
from app.models.core.superquery import SuperQuery

def load_object(
    object_type: str,
    name: str,
    return_instance: bool = True,
    criteria: dict = None,
    hooks: dict = None
) -> dict:
    """
    Charge dynamiquement un objet depuis la base (modèle, module, template...).

    Args:
        object_type (str): Type de l'objet (ex: "models", "modules", "templates")
        name (str): Identifiant ou nom de l'objet à charger
        return_instance (bool): True = objet instancié, False = données brutes
        criteria (dict): Filtres supplémentaires à appliquer
        hooks (dict): Hooks à déclencher avant/après chargement

    Returns:
        dict: {
            "success": bool,
            "result": object | dict,
            "message": str,
            "hooks": dict (facultatif)
        }
    """
    if not criteria:
        criteria = {}

    try:
        # Appel à la super requête enrichie
        query_data = {
            "type_element": object_type,
            "table": name,
            "filters": criteria
        }

        results = SuperQuery.execute_with_metadata(query_data)

        if not results:
            return {
                "success": False,
                "result": None,
                "message": f"Aucun objet trouvé pour {object_type}.{name} avec critères {criteria}",
                "hooks": hooks or {}
            }

        result = results[0]
        metas = result.get("metas", {})

        # Si on ne veut pas d'objet instancié, on retourne brut
        if not return_instance:
            return {
                "success": True,
                "result": result,
                "message": f"Objet {name} (type {object_type}) chargé sous forme brute.",
                "hooks": hooks or {}
            }

        # Récupération du chemin Python depuis les metas
        module_path = metas.get("url")

        # Fallback automatique pour objets courants si non défini
        if not module_path:
            default_paths = {
                "page": "app.models.elements.page.page",
                "module": "app.models.elements.page.module"
                # Tu peux ajouter ici "template", "action", etc.
            }
            module_path = default_paths.get(name)

        if not module_path:
            return {
                "success": False,
                "result": result,
                "message": f"Aucun chemin Python défini pour charger dynamiquement {name}.",
                "hooks": hooks or {}
            }

        # Chargement dynamique
        module = importlib.import_module(module_path)
        class_name = module_path.split(".")[-1].capitalize()
        klass = getattr(module, class_name)
        obj = klass()

        # Injection des données dans l'instance
        if hasattr(obj, "load") and callable(getattr(obj, "load")):
            obj.load(result)
        else:
            for k, v in result.items():
                setattr(obj, k, v)

        return {
            "success": True,
            "result": obj,
            "message": f"Objet {name} instancié avec succès.",
            "hooks": hooks or {}
        }

    except Exception as e:
        return {
            "success": False,
            "result": None,
            "message": f"[ERREUR] superloader.load_object : {e}",
            "hooks": hooks or {},
            "traceback": traceback.format_exc()
        }


