pythonCopierModifierfrom app.models.core.superquery import SuperQuery
from app.models.core.superquery_components import GroupComponent
from app.models.core.model_loader import load_model_class
import importlib


class SuperLoader:
    @staticmethod
    def load(object_type, name, return_instance=False, criteria=None, hooks=None):
        try:
            # Auto-format du dictionnaire criteria s'il n'est pas déjà un GroupComponent
            if isinstance(criteria, dict):
                formatted = {}
                for key in ["columns", "relations", "tags", "metas", "datas"]:
                    if key in criteria:
                        formatted[f"add_{key}"] = criteria.pop(key)
                criteria = GroupComponent(logical_operator="AND", **formatted, **criteria)

            results = SuperQuery.execute_with_metadata({
                "type_element": object_type,
                "table": name,
                "filters": criteria,
                "hooks": hooks
            })

            if not results:
                return None

            # Si ce n'est pas une classe (donc un modèle classique), on renvoie juste le dictionnaire
            if not return_instance:
                return results[0]

            # Si c'est une classe (ex: un objet avec des méthodes), on instancie
            model_class = load_model_class(object_type, name)
            instance = model_class(results[0])
            return instance

        except Exception as e:
            print(f"[ERREUR] SuperLoader.load : {e}")
            return None


def superloader(object_type, name, return_instance=False, criteria=None, hooks=None):
    return SuperLoader.load(object_type, name, return_instance, criteria, hooks)


