Voici la version mise à jour et corrigée du fichier superloader.py avec la gestion du GroupComponent intégrée (et sans changer la logique que tu avais validée) :
pythonCopierModifierimport importlib
import traceback
from app.models.core.superquery import ObjectCriteria, QueryBuilder, QueryExecute, SuperQuery
from app.models.core.querybuilder import GroupComponent


class SuperLoader:
    """
    Classe pour charger dynamiquement des objets depuis la base de données.
    Fournit une interface simplifiée pour SuperQuery.
    """

    def __call__(self, object_type, name, criteria=None, hooks=None):
        return self.load(object_type, name, False, criteria, hooks)

    @staticmethod
    def load(object_type, name, return_instance=False, criteria=None, hooks=None):
        if criteria is None:
            criteria = {}

        try:
            # Si criteria est déjà un GroupComponent, on l'utilise directement
            if hasattr(criteria, "logical_operator"):
                filters = criteria
            else:
                # Sinon, on reconstruit un ObjectCriteria
                obj_criteria = ObjectCriteria()
                obj_criteria.set_type(object_type)

                if "columns" in criteria:
                    for key, value in criteria["columns"].items():
                        obj_criteria.add_column(key, "=", value)

                if "metas" in criteria:
                    for key, value in criteria["metas"].items():
                        obj_criteria.add_meta(key, "=", value)

                if "tags" in criteria:
                    for value in criteria["tags"]:
                        obj_criteria.add_tag(value)

                if "relations" in criteria:
                    for direction, rels in criteria["relations"].items():
                        for relation_type, rel_value in rels.items():
                            obj_criteria.add_relation(relation_type, rel_value, direction)

                filters = obj_criteria  # On utilise cet ObjectCriteria comme filtre

            # Exécution de la requête
            results = SuperQuery.execute_with_metadata({
                "type_element": object_type,
                "table": name,
                "filters": filters
            })

            if not results:
                print(f"[INFO] Aucun résultat trouvé pour {object_type}.{name} avec {criteria}")
                return None

            enriched_results = SuperQuery.enrich_objects_with_metadata(results)
            result = enriched_results[0] if enriched_results else None

            if not result:
                return None

            # Gestion du chargement dynamique si c'est une classe
            metas = result.get("metas", {})
            code_type = metas.get("code_type", "").lower()
            module_path = metas.get("url")

            if code_type == "class" and module_path:
                try:
                    module = importlib.import_module(module_path)
                    class_name = module_path.split(".")[-1].capitalize()

                    if hasattr(module, class_name):
                        klass = getattr(module, class_name)
                        instance = klass()

                        if not return_instance:
                            for k, v in result.items():
                                setattr(instance, k, v)
                            return instance
                        else:
                            if hasattr(instance, "load") and callable(instance.load):
                                instance.load(result)
                            else:
                                for k, v in result.items():
                                    setattr(instance, k, v)
                            return instance
                except Exception as e:
                    print(f"[ERREUR] Chargement dynamique échoué pour {module_path} : {e}")
                    print(traceback.format_exc())

            return result

        except Exception as e:
            print(f"[ERREUR] SuperLoader.load : {e}")
            print(traceback.format_exc())
            return None


# Créer une instance unique pour l'utilisation globale
superloader = SuperLoader()


