from app.models.core.superquery import SuperQuery, GroupComponent
from app.models.core.superquery import ObjectCriteria
import importlib

class SuperLoader:
    @staticmethod
    def load(object_type, name, instantiate=False, criteria=None):
        try:
            # Si aucun critère n’est fourni, on en crée un vide
            if criteria is None:
                criteria = {}

            # Si c'est un dict, on le transforme en ObjectCriteria
            if isinstance(criteria, dict):
                crit = ObjectCriteria()
                if "columns" in criteria:
                    for key, value in criteria["columns"].items():
                        crit.add_column(key, "=", value)
                if "metas" in criteria:
                    for key, value in criteria["metas"].items():
                        crit.add_meta(key, "=", value)
                if "tags" in criteria:
                    for tag in criteria["tags"]:
                        crit.add_tag(tag)
                if "relations" in criteria:
                    for relation_name, target_id in criteria["relations"].items():
                        crit.add_relation(relation_name, target_id)
                filters = crit
            else:
                filters = criteria  # déjà un ObjectCriteria ou GroupComponent

            # Exécution de la requête principale
            results = SuperQuery.execute_with_metadata({
                "type_element": object_type,
                "table": name,
                "filters": filters
            })

            # Si rien trouvé
            if not results:
                return None

            # Si on demande une instance brute
            if not instantiate:
                return results[0] if len(results) == 1 else results

            # Sinon, on instancie les objets à partir de leur modèle Python
            model_module = f"app.models.{object_type}.{name}"
            model_class_name = name.capitalize()

            module = importlib.import_module(model_module)
            model_class = getattr(module, model_class_name)

            objects = [model_class(**item) for item in results]

            return objects[0] if len(objects) == 1 else objects

        except Exception as e:
            print(f"[ERREUR] SuperLoader.load : {e}")
            return None


