def enrich_objects_with_metadata(objects):
    """Enrichit une liste d'objets avec leurs métadonnées, relations et tags, en regroupant les relations par type."""
    print(f"[DEBUG] enrich_objects_with_metadata: {objects}")
    if not objects:
        print("[DEBUG] Pas d'objets à enrichir")
        return []

    if isinstance(objects, dict):
        print("[DEBUG] Conversion d'un seul objet en liste")
        objects = [objects]

    print(f"[DEBUG] Enrichissement de {len(objects)} objets")

    for obj in objects:
        obj_id = obj['id']
        print(f"[DEBUG] Enrichissement de l'objet {obj_id}")

        metas = SuperQuery.get_metas_by_object_id(obj_id)
        obj['metas'] = {meta['meta_key']: meta['meta_value'] for meta in metas}
        print(f"[DEBUG] Métadonnées ajoutées pour objet {obj_id}: {obj['metas']}")

        obj['tags'] = SuperQuery.get_tags_by_object_id(obj_id)
        print(f"[DEBUG] Tags ajoutés pour objet {obj_id}: {obj['tags']}")

        source_relations = SuperQuery.get_relations_by_object_id(obj_id, as_source=True)
        print(f"[DEBUG] Relations source trouvées pour objet {obj_id}: {len(source_relations)}")

        target_relations = SuperQuery.get_relations_by_object_id(obj_id, as_source=False)
        print(f"[DEBUG] Relations cible trouvées pour objet {obj_id}: {len(target_relations)}")

        obj['relations'] = {
            'as_source': {},
            'as_target': {}
        }

        def group_by_type(relations):
            grouped = {}
            for rel in relations:
                rel_type = SuperQuery.get_object_type_by_id(rel['id']) or 'unknown'
                plural_type = rel_type + 's' if not rel_type.endswith('s') else rel_type
                if plural_type not in grouped:
                    grouped[plural_type] = []
                grouped[plural_type].append({
                    'id': rel['id'],
                    'name': rel['name'],
                    'ident': rel['ident']
                })
            return grouped

        # Organiser les relations sources
        for rel in source_relations:
            rel_name = rel['relation_name']
            if rel_name not in obj['relations']['as_source']:
                obj['relations']['as_source'][rel_name] = {}
            grouped = group_by_type([rel])
            for t, items in grouped.items():
                obj['relations']['as_source'][rel_name].setdefault(t, []).extend(items)

        # Organiser les relations cibles
        for rel in target_relations:
            rel_name = rel['relation_name']
            if rel_name not in obj['relations']['as_target']:
                obj['relations']['as_target'][rel_name] = {}
            grouped = group_by_type([rel])
            for t, items in grouped.items():
                obj['relations']['as_target'][rel_name].setdefault(t, []).extend(items)

        print(f"[DEBUG] Enrichissement terminé pour objet {obj_id}")

    return objects


